import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';

const Payments = () => {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  // Mock payment data
  const mockPayments = [
    {
      id: 1,
      bookingId: 1,
      carName: 'Tesla Model S',
      amount: 750,
      method: 'Credit Card',
      status: 'completed',
      date: '2024-01-10',
      transactionId: 'TXN-001-2024'
    },
    {
      id: 2,
      bookingId: 2,
      carName: 'BMW X5',
      amount: 600,
      method: 'Debit Card',
      status: 'completed',
      date: '2023-12-28',
      transactionId: 'TXN-002-2023'
    },
    {
      id: 3,
      bookingId: 3,
      carName: 'Mercedes C-Class',
      amount: 200,
      method: 'Credit Card',
      status: 'pending',
      date: '2024-01-20',
      transactionId: 'TXN-003-2024'
    },
    {
      id: 4,
      bookingId: 4,
      carName: 'Audi A4',
      amount: 400,
      method: 'Credit Card',
      status: 'refunded',
      date: '2023-12-10',
      transactionId: 'TXN-004-2023'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setPayments(mockPayments);
      setLoading(false);
    }, 500);
  }, []);

  const filteredPayments = payments.filter(payment => {
    if (filter === 'all') return true;
    return payment.status === filter;
  });

  const getStatusBadge = (status) => {
    const statusClasses = {
      completed: 'status-completed',
      pending: 'status-pending',
      refunded: 'status-refunded',
      failed: 'status-cancelled'
    };
    return (
      <span className={`status-badge ${statusClasses[status]}`}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  const totalSpent = payments
    .filter(p => p.status === 'completed')
    .reduce((sum, p) => sum + p.amount, 0);

  const totalPending = payments
    .filter(p => p.status === 'pending')
    .reduce((sum, p) => sum + p.amount, 0);

  return (
    <div className="dashboard-page">
      <Sidebar />
      
      <div className="dashboard-content">
        <div className="page-header">
          <h1>Payments</h1>
          <p>View your payment history and manage transactions</p>
        </div>

        {/* Payment Stats */}
        <div className="payment-stats">
          <div className="payment-stat-card">
            <div className="stat-icon">💵</div>
            <div className="stat-details">
              <h3>₱{totalSpent.toLocaleString()}</h3>
              <p>Total Spent</p>
            </div>
          </div>
          
          <div className="payment-stat-card">
            <div className="stat-icon">⏳</div>
            <div className="stat-details">
              <h3>₱{totalPending.toLocaleString()}</h3>
              <p>Pending Payments</p>
            </div>
          </div>
          
          <div className="payment-stat-card">
            <div className="stat-icon">📊</div>
            <div className="stat-details">
              <h3>{payments.length}</h3>
              <p>Total Transactions</p>
            </div>
          </div>
        </div>

        {/* Filter Tabs */}
        <div className="filter-tabs">
          <button 
            className={`filter-tab ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            All ({payments.length})
          </button>
          <button 
            className={`filter-tab ${filter === 'completed' ? 'active' : ''}`}
            onClick={() => setFilter('completed')}
          >
            Completed ({payments.filter(p => p.status === 'completed').length})
          </button>
          <button 
            className={`filter-tab ${filter === 'pending' ? 'active' : ''}`}
            onClick={() => setFilter('pending')}
          >
            Pending ({payments.filter(p => p.status === 'pending').length})
          </button>
          <button 
            className={`filter-tab ${filter === 'refunded' ? 'active' : ''}`}
            onClick={() => setFilter('refunded')}
          >
            Refunded ({payments.filter(p => p.status === 'refunded').length})
          </button>
        </div>

        {/* Payments List */}
        {loading ? (
          <div className="loading">Loading payments...</div>
        ) : filteredPayments.length === 0 ? (
          <div className="empty-state">
            <p>No payments found</p>
          </div>
        ) : (
          <div className="payments-list">
            <table className="payments-table">
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Car</th>
                  <th>Amount</th>
                  <th>Method</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredPayments.map(payment => (
                  <tr key={payment.id}>
                    <td>{payment.date}</td>
                    <td>
                      <div className="payment-car">
                        <strong>{payment.carName}</strong>
                        <span>Booking #{payment.bookingId}</span>
                      </div>
                    </td>
                    <td className="payment-amount">₱{payment.amount.toLocaleString()}</td>
                    <td>{payment.method}</td>
                    <td>{getStatusBadge(payment.status)}</td>
                    <td>
                      <button className="btn btn-small btn-secondary">
                        View Receipt
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Payments;
